import unittest

class TestSolution(unittest.TestCase):
    def test_basic_1(self):
        self.assertEqual(count_permutations(5, 3), 60)

    def test_basic_2(self):
        self.assertEqual(count_permutations(4, 4), 24)

    def test_basic_3(self):
        self.assertEqual(count_permutations(6, 2), 30)

    def test_hidden_r_zero(self):
        self.assertEqual(count_permutations(5, 0), 1)

    def test_hidden_r_greater_than_n(self):
        self.assertEqual(count_permutations(3, 5), 0)

    def test_hidden_n_zero_r_zero(self):
        self.assertEqual(count_permutations(0, 0), 1)

    def test_hidden_n_equals_one(self):
        self.assertEqual(count_permutations(1, 1), 1)

    def test_hidden_larger_values(self):
        self.assertEqual(count_permutations(10, 3), 720)

    def test_hidden_n_equals_r(self):
        self.assertEqual(count_permutations(6, 6), 720)

    def test_hidden_large_n_small_r(self):
        self.assertEqual(count_permutations(20, 2), 380)

